"""HLD Case Studies: Bitly, Dropbox, Local Delivery Service, News Aggregator, Ticketmaster, FB News Feed, Tinder, LeetCode, WhatsApp, Yelp."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def bitly_lesson() -> Lesson:
    return Lesson(id="hld-bitly", number=200, title="Bitly (Shortlink Generator)",
        focus=("base58 encoding","hash collision","short url key","redirection latency","counter service"),
        overview="Design a scalable, highly available URL shortening service like Bitly.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("bit-1","Why is Base58 preferred over Base64 for URL shortening?","easy",("case-study",),
             ("Base58 excludes visually ambiguous characters like 0, O, I, and l", "Base64 requires additional padding characters that invalidate URLs", "Base58 uses symmetric encryption keys for faster encoding", "Base64 is not compatible with standard HTTP redirect headers"),0,
             "Base58 excludes 0, O, I, l, +, and / to avoid user confusion and copy-paste issues."),
        quiz("bit-2","Which HTTP status code is best for Bitly redirects to allow search engine analytics?","medium",("case-study",),
             ("308 Permanent Redirect to ensure modern browser standards are strictly met", "307 Temporary Redirect to prevent browser caching of security headers", "301 Moved Permanently to cache redirects and reduce Bitly server load", "302 Found to force the browser to hit Bitly on every click for telemetry"),3,
             "302 Found ensures the redirect isn't cached permanently by the browser, allowing Bitly to track analytics on every click."),
        quiz("bit-3","How many characters are needed for a Base58 key to support 100 billion unique URLs?","medium",("case-study",),
             ("5 characters (58^5 ≈ 656 million keys)", "7 characters (58^7 ≈ 2.2 trillion keys)", "6 characters (58^6 ≈ 38 billion keys)", "8 characters (58^8 ≈ 128 trillion keys)"),1,
             "7 characters yields 58^7 ≈ 2.2 trillion combinations, which easily accommodates 100 billion URLs."),
        quiz("bit-4","What is the main drawback of using MD5 hashing (first 7 characters) for Bitly keys?","hard",("case-study",),
             ("First 7 characters will inevitably cause high collision rates, requiring resolution", "MD5 hashes are computed too slowly for a high-throughput write pipeline", "Relational databases cannot index hex-encoded string columns efficiently", "MD5 is cryptographically broken and prone to reverse-engineering attacks"),0,
             "Truncating MD5 (or SHA-256) keys to 7 characters dramatically increases the probability of hash collisions."),
        quiz("bit-5","What is the role of a Range Keeper (Counter Service) in Bitly?","hard",("case-study",),
             ("To monitor network bandwidth utilization across active global edge locations", "To maintain a sliding window for rate-limiting excessive write requests", "To coordinate distributed locking across active database replication pipelines", "To pre-allocate ranges of unique sequential IDs to web servers, preventing duplicates"),3,
             "A range keeper (e.g. using ZooKeeper) dispenses blocks of unique IDs to instances to avoid centralized lock contention."),
        quiz("bit-6","Which database is best suited for storing Bitly's URL mappings?","medium",("case-study",),
             ("A graph database (like Neo4j) to map relationship paths between users and links", "A column-oriented analytical database (like ClickHouse) optimized for raw writes", "A key-value or wide-column store (like DynamoDB) for O(1) primary key lookups", "A relational database with heavy JOIN capabilities for analytics tracking"),2,
             "Bitly's workload is dominated by simple key-value lookups: short_url → long_url. NoSQL KV stores scale horizontally with ease."),
        quiz("bit-7","How should Bitly handle read scalability for highly viral links?","medium",("case-study",),
             ("By enforcing database lock escalation to prevent concurrent read modifications", "By vertically scaling the relational database write nodes during peak hours", "By caching viral mappings in a distributed in-memory cache like Redis or Memcached", "By writing all active requests to a messaging queue for asynchronous processing"),2,
             "Caching hot URL mappings in memory avoids hitting the database on every lookup for viral links."),
        quiz("bit-8","What is the most effective cache eviction policy for Bitly's redirect cache?","medium",("case-study",),
             ("Least Frequently Used (LFU) to protect historical corporate accounts", "Random Eviction to minimize the processing overhead of tracking access times", "First-In, First-Out (FIFO) to maintain a highly predictable memory footprint", "Least Recently Used (LRU) to keep recently active/viral links cached"),3,
             "LRU keeps active, recently clicked links in memory while naturally evicting old, inactive ones."),
        quiz("bit-9","How do you handle custom alias requests in Bitly?","hard",("case-study",),
             ("Compute a custom MD5 hash of the alias and enforce range partitioning", "Run a distributed lock across all application servers on every creation", "Store them in a separate table and check if the custom alias is already taken", "Convert the custom alias to Base58 and verify it matches the counter prefix"),2,
             "Custom aliases require checking a unique constraint or checking existence in a dedicated index/table before creation."),
        quiz("bit-10","Why is standard sequential auto-incrementing ID in a single DB bad for Bitly's keys?","hard",("case-study",),
             ("It forces all redirect requests to hit the same primary write replica", "Sequential values cannot be encoded using Base58 formats", "It makes the short URLs easily guessable, enabling malicious scraping and bulk crawling", "Auto-increment keys can only represent a maximum of 4 billion unique entries"),2,
             "Sequential IDs are guessable (allowing scraping of private links) and create a centralized write bottleneck."),
        quiz("bit-11","What is the optimal URL validation strategy before shortening?","easy",("case-study",),
             ("Encrypt the target URL using AES-256 to verify data integrity", "Run a complete network ping to the target domain on every request", "Verify domain format and run a regex match on standard protocols (HTTP/HTTPS)", "Upload the target URL to a global CDN edge to check availability"),2,
             "Fast validation via domain parsing and regex checks ensures system stability without waiting on downstream networks."),
        quiz("bit-12","To handle 10,000 writes/sec, what capacity estimation for storage is needed if each mapping is 500 bytes?","medium",("case-study",),
             ("4.32 TB per day", "432 MB per day", "432 GB per day", "50 MB per day"),2,
             "10,000 writes/sec × 500 bytes × 86,400 seconds/day ≈ 432 GB of data generated daily."),
        quiz("bit-13","Which mechanism avoids the 'thundering herd' when a hot cache entry expires in Bitly?","hard",("case-study",),
             ("Using a mutex lock (e.g. single-flight pattern) so only one server regenerates the cache key", "Enforcing synchronous writes to the database replicas", "Using round-robin DNS to distribute traffic away from the hot caching node", "Configuring a random TTL for all cached URL mappings"),0,
             "Using a single-flight or distributed lock ensures only one worker queries the database on a cache miss, protecting backends."),
        quiz("bit-14","How can we implement geo-routing for Bitly redirections?","medium",("case-study",),
             ("Using Anycast DNS to route the client's request to the nearest available data center", "Enforcing client-side JavaScript geolocation checks before executing redirects", "Replicating the entire key namespace to a single centralized server in North America", "Sharding the URL database based on the country code of the target long URL"),0,
             "Anycast DNS routes client queries to the nearest physical location sharing the same IP address, minimizing latency."),
        quiz("bit-15","What is the advantage of using a Bloom filter in Bitly's write pipeline?","hard",("case-study",),
             ("It speeds up the creation of Base58 encoding sequences", "It resolves hash collisions between shortened string keys", "It acts as a distributed cache layer for long URLs", "It quickly checks if a custom alias is NOT taken without querying the database"),3,
             "Bloom filters tell us with 100% certainty if a custom alias is *not* in the database, avoiding unnecessary disk reads."),
        quiz("bit-16","How does a Bitly server perform the actual redirection?","easy",("case-study",),
             ("By injecting a custom <iframe> pointing to the long URL into the client's browser", "By running a server-side cURL request and rendering the destination page HTML", "By writing the target URL to the client's local storage via a cookies header", "By returning a 302 Found response with the 'Location' header set to the target URL"),3,
             "Redirection is handled cleanly at the HTTP layer by setting the 'Location' header along with a 3xx status code."),
        quiz("bit-17","What is the primary trade-off of using a 301 vs 302 redirect code in Bitly?","medium",("case-study",),
             ("301 is faster but prevents tracking click metrics; 302 is slower but allows analytics",
              "301 requires complex server-side encryption; 302 works over plain unencrypted HTTP",
              "301 causes modern web browsers to throw certificate warnings; 302 bypasses them",
              "301 works only on mobile devices; 302 is designed exclusively for desktop environments"),0,
             "301 redirects are cached permanently by browsers, bypassing Bitly next time and preventing click tracking."),
        quiz("bit-18","If you need to expire links after a certain date, how is this best implemented in a NoSQL store?","medium",("case-study",),
             ("Implement a secondary relational index to sort all records by timestamp", "Use a database TTL (Time-To-Live) feature on the mapping record", "Run a complete daily database scan and delete expired records row-by-row", "Reject all requests with timestamps older than the server's current epoch"),1,
             "Many NoSQL stores (like DynamoDB or Redis) support native TTLs that automatically purge expired records in the background."),
        quiz("bit-19","What is a major advantage of using a distributed Snowflake-like ID generation over ZooKeeper range allocation?","hard",("case-study",),
             ("Snowflake IDs are inherently secure and cannot be reversed to reveal timestamps", "Snowflake avoids the need for consistent hashing rings in database replication", "Snowflake IDs are shorter and require less database storage capacity", "Snowflake-like generators have zero coordination overhead and do not require a network call"),3,
             "Snowflake IDs are generated locally using timestamps, machine IDs, and sequences, removing central network coordinator bottle-necks."),
        quiz("bit-20","How does Bitly prevent abuse (e.g., shortening spam or malicious phishing URLs)?","medium",("case-study",),
             ("By storing shortened URLs as encrypted blobs that cannot be read by third parties", "By blocking all non-HTTPS destination domains automatically", "By requiring multi-factor authentication for every single shortening attempt", "By validating destination domains against a real-time safety database (e.g. Google Safe Browsing)"),3,
             "Integrating a real-time safety API in the creation pipeline blocks malicious URLs before they are written to the database."),
    ))

def dropbox_lesson() -> Lesson:
    return Lesson(id="hld-dropbox", number=201, title="Dropbox (Cloud Storage)",
        focus=("chunking","rolling hash","metadata DB","block server","sync conflict"),
        overview="Design a secure, highly scalable cloud storage service like Dropbox with efficient sync.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("dbx-1","How does Dropbox optimize network bandwidth when syncing modified large files?","medium",("case-study",),
             ("By converting binary files into Base64 format to bypass standard proxy firewalls", "By scheduling all uploads during low-traffic overnight hours", "By compressing the entire file using high-ratio compression before transmission", "By chunking files into smaller blocks and only uploading modified blocks"),3,
             "Splitting files into chunks (typically 4MB) and only uploading changed blocks (delta sync) saves massive bandwidth."),
        quiz("dbx-2","What is content-addressable storage (CAS) in Dropbox's block storage?","hard",("case-study",),
             ("A database index that maps file names to physical server rack coordinates", "A routing strategy that directs users to the nearest storage node via Anycast", "Addressing storage blocks by their SHA-256 hash, enabling deduplication", "Encrypting file content at rest using a customer-provided master key"),2,
             "Hashing block contents allows the system to identify duplicates globally. If two users upload the same block, store it once."),
        quiz("dbx-3","Why does Dropbox separate file metadata storage from the actual block storage?","hard",("case-study",),
             ("Metadata must be encrypted with symmetric keys while block storage must remain public", "Relational databases cannot handle binary storage types like files or blobs", "Metadata requires low-latency, transactional query updates; blocks require high-capacity, immutable object storage", "To satisfy legal compliance laws that prohibit storing file names alongside file contents"),2,
             "Metadata is relational, fast, and constantly changing (names, folders, dates). Blocks are large, static blobs (stored in S3)."),
        quiz("dbx-4","What is the role of the client-side Sync Engine in Dropbox?","medium",("case-study",),
             ("To index the entire internet for local file matching", "To run full-text search queries across the global cloud storage servers", "To host local HTTP servers for browser-based sharing networks", "To monitor the local directory, detect changes, handle chunking, and coordinate block uploads"),3,
             "The local sync engine handles chunking, hashing, monitoring filesystem events, and uploading changed chunks to block servers."),
        quiz("dbx-5","What is Rabin Fingerprinting used for in Dropbox chunking?","hard",("case-study",),
             ("To verify user biometrics for secure file sharing permission checks", "To sign client request tokens and prevent unauthorized access to file blocks", "To dynamically detect chunk boundaries using a sliding window rolling hash", "To compress text blocks before storing them on S3 storage nodes"),2,
             "Rabin fingerprinting is a rolling hash algorithm that finds shift-resistant boundaries, ensuring changed files only affect local chunks."),
        quiz("dbx-6","Which technology is best for real-time notifications when files change on another device?","medium",("case-study",),
             ("HTTP Long Polling or WebSockets to push update notifications immediately", "Sending batch SMS notifications to registered client devices", "Relational database trigger replication across geographic regions", "Running a continuous client cron job that polls the metadata DB every 500ms"),0,
             "Persistent connections (WebSockets or long polling) allow the notification server to instantly wake up the desktop client to sync."),
        quiz("dbx-7","How are sync conflicts resolved when two users edit the same file offline simultaneously?","medium",("case-study",),
             ("The database locks the file record indefinitely until a system administrator intervenes", "The server merges the changes automatically using complex semantic natural language processing", "The server rejects the second update and deletes the client's local modifications", "The server creates a second copy of the file marked as 'conflicted copy' to let users resolve manually"),3,
             "Automatic merges are risky. Creating a 'conflicted copy' preserves both edits, giving the user final control over reconciliation."),
        quiz("dbx-8","Where should the file allocation table (mapping of files to block IDs) be stored?","hard",("case-study",),
             ("On client devices only to optimize server storage capacity", "Directly on the block storage servers alongside the raw block bytes", "In a strongly consistent, highly transactional metadata database", "In an eventually consistent distributed cache without database backup"),2,
             "The file-to-blocks mapping represents the document structure. It must be stored in a reliable database (e.g. Postgres with ACID)."),
        quiz("dbx-9","What is the benefit of a client-side database (e.g. SQLite) in Dropbox?","medium",("case-study",),
             ("It acts as a primary backup of the cloud storage metadata", "It caches other users' shared folders for peer-to-peer delivery", "It encrypts the client operating system's file system boot records", "It tracks local file states, block hashes, and modification times to detect changes quickly offline"),3,
             "A local database allows the client to immediately identify which files have changed without querying the server on startup."),
        quiz("dbx-10","How does block deduplication save storage space in cloud storage systems?","medium",("case-study",),
             ("By reducing the resolution of stored image and video files", "By compressing files using standard zip algorithms before saving them", "By deleting inactive folders that haven't been accessed in over 90 days", "By storing only one unique instance of a block across the entire system, even if owned by multiple users"),3,
             "If multiple users upload identical content, the server checks the hash, sees it already exists, and just adds a metadata link."),
        quiz("dbx-11","What is the security risk of naive client-side deduplication?","hard",("case-study",),
             ("It corrupts block structures because hash collisions are highly probable", "It slows down file transfer rates due to expensive cryptographic calculations", "It allows an attacker to verify the existence of a file in the system by checking if an upload is skipped", "It requires clients to share their private decryption keys with other users"),2,
             "Attacker has a hash of a target file. They pretend to upload it. If the server says 'already have it, upload skipped', the attacker knows it exists."),
        quiz("dbx-12","How do you secure block storage access so users can only download their own files?","hard",("case-study",),
             ("Make all object storage buckets private and serve blocks through pre-signed URLs verified by metadata permissions", "Require users to SSH directly into the storage hardware nodes", "Obfuscate the block storage URLs by adding random strings to the names", "Encrypt the entire storage volume with a single global master key"),0,
             "Pre-signed URLs (e.g. AWS S3 Pre-signed URLs) grant time-limited read access to specific blocks after verifying the user's metadata permission."),
        quiz("dbx-13","What is the role of the Metadata Cache in Dropbox?","medium",("case-study",),
             ("To store temporary file blocks during chunk reconstruction", "To store raw user passwords for authentication speed", "To route client requests to the topologically nearest metadata server", "To cache database rows for fast query response times when rendering the UI"),3,
             "Caching metadata (e.g., directory listings) in Memcached or Redis dramatically reduces the load on relational database instances."),
        quiz("dbx-14","Why is strong consistency preferred over eventual consistency for Dropbox metadata?","hard",("case-study",),
             ("To allow rapid compression of block lists during client transfers", "Because eventual consistency is incompatible with secure SSL/TLS communication", "To maximize write throughput across geographically dispersed storage zones", "To avoid conflicting views of the folder structure (e.g. seeing a deleted folder reappear)"),3,
             "Eventual consistency can cause files to reappear or show outdated hierarchies, breaking user trust and file sync logic."),
        quiz("dbx-15","What does the block server do in Dropbox?","medium",("case-study",),
             ("It routes client push notifications", "It indexes files for full-text search", "It manages the relational schema for user authentication", "It uploads and downloads raw block data to and from the object storage"),3,
             "The block server handles raw block data transfers to and from the S3 storage engine, keeping the metadata server uncluttered."),
        quiz("dbx-16","How should Dropbox handle very small files (e.g., under 100 bytes)?","hard",("case-study",),
             ("Keep them stored only in the client's local SQLite database", "Store them directly in the metadata database row to avoid the high overhead of S3 object creation", "Upload them as standard 4MB blocks padded with empty zeros", "Reject them and require users to combine them into zip archives first"),1,
             "Inline storage of tiny payloads in the metadata table avoids S3 latency, connection cost, and small-file storage overhead."),
        quiz("dbx-17","What is the best way to implement file versioning?","medium",("case-study",),
             ("Overwrite the existing metadata row but keep a backup log of old file names",
              "Keep metadata records immutable, using version numbers or timestamps to point to new block configurations",
              "Duplicate the entire physical block storage contents for every file edit",
              "Force clients to rename files with version suffixes (e.g., doc_v1, doc_v2)"),1,
             "Versioning is best modeled by keeping metadata rows history-aware (e.g. a ledger), linking each file version to its list of block IDs."),
        quiz("dbx-18","What mechanism allows Dropbox to handle deep folder synchronization efficiently?","hard",("case-study",),
             ("Using a nested set model or path enumeration in the database to fetch directory structures in one query", "Sharding the folder structure database by the hash of the individual file names", "A recursive query traversing the entire directory tree on every sync loop", "Enforcing a maximum folder depth limit of 3 layers for all accounts"),0,
             "Path enumeration or materialized paths (e.g. /user1/photos/2026/trip) avoids nested recursive JOINs when fetching folder contents."),
        quiz("dbx-19","How is encryption-at-rest typically managed for cloud storage blocks?","medium",("case-study",),
             ("Blocks are encrypted using unique data keys before storage, with keys managed by a Key Management Service (KMS)", "Object storage devices automatically detect file types and encrypt only sensitive formats", "Encryption keys are hardcoded into the block storage server source code", "All files are stored as plain text and encrypted on-the-fly by the user's browser"),0,
             "Enforcing KMS-managed key rotation keeps data highly secure at rest without exposing plain text files to storage providers."),
        quiz("dbx-20","Which strategy mitigates S3 rate limits during massive concurrent sync operations?","hard",("case-study",),
             ("Using a single shared S3 key for all blocks stored in the cluster", "Hashing block keys to distribute them evenly across S3 partition namespaces", "Enforcing a strict queue that processes one sync request at a time sequentially", "Deploying local caching hardware inside the client's local area network"),1,
             "S3 partition limits are based on key prefixes. Randomizing prefixes (e.g., prepending hash digits to block paths) avoids partition hotspots."),
    ))

def delivery_service_lesson() -> Lesson:
    return Lesson(id="hld-delivery-service", number=202, title="Local Delivery Service",
        focus=("quadtree","spatial index","driver routing","order state machine","geohash"),
        overview="Design a real-time on-demand delivery service like DoorDash or UberEats.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("del-1","Which coordinate indexing system is best for searching nearby restaurants or drivers in real-time?","medium",("case-study",),
             ("A centralized relational database view that runs the Haversine formula on every request", "Sharding the database tables based on restaurant name strings", "Geohash or Quadtree indexes to group coordinates into 2D spaces", "Standard B-tree indexes on two columns: latitude and longitude"),2,
             "Standard B-trees cannot query two dimensions efficiently. Geohashes or Quadtrees index 2D locations into a single dimension."),
        quiz("del-2","How does a Quadtree index handle highly dense areas like downtown Manhattan?","hard",("case-study",),
             ("By shifting coordinate data to adjacent lower-density nodes", "By recursively splitting overcrowded nodes into 4 child sub-quadrants", "By rejecting new points of interest once a node capacity limit is reached", "By dropping the precision of latitude/longitude records to save memory"),1,
             "Quadtrees dynamically subdivide regions into four sub-quadrants when the number of points in a cell exceeds a threshold."),
        quiz("del-3","What is a major limitation of a static in-memory Quadtree for dynamic driver location tracking?","hard",("case-study",),
             ("Quadtrees are incompatible with modern GPS device coordinate updates", "Static trees cannot support more than 100 concurrent coordinate points", "Quadtrees cannot be loaded into server RAM structures", "Drivers move continuously, making constant tree rebalancing and lock contention highly expensive"),3,
             "Rebalancing quadtrees continuously for fast-moving drivers is too slow. Better to use Redis Geospatial (Geohash-based) for drivers."),
        quiz("del-4","How does a geohash represent a location?","medium",("case-study",),
             ("A 64-bit integer representing the distance from the Greenwich meridian", "A base32 string representing a specific rectangular grid cell on Earth", "An encrypted key containing the user's physical IP address", "A coordinate pair formatted as JSON arrays"),1,
             "Geohash converts 2D coordinates into a single base32 string. Longer strings represent smaller, more precise grid squares."),
        quiz("del-5","How should the Order Status workflow be managed to avoid race conditions (e.g. multiple drivers accepting)?","hard",("case-study",),
             ("By allowing drivers to write status updates directly to local memory variables", "By broadcasting order status changes via eventually consistent messaging channels", "By utilizing a strongly consistent database state machine with optimistic locking on the order version", "By deleting and recreating the order record on every status transition"),2,
             "Optimistic locking (checking version before update) ensures only one driver can successfully transition an order to 'accepted'."),
        quiz("del-6","Which technology is best for pushing real-time order tracking updates to the customer's phone?","medium",("case-study",),
             ("A relational database trigger that updates the customer's local browser cookies", "Server-Sent Events (SSE) or WebSockets for live low-latency unidirectional coordinate updates", "Running background SMS query pings to locate the client device", "Sending repeated transactional email updates every time the driver moves 10 meters"),1,
             "SSE or WebSockets maintain persistent connections, enabling high-frequency location updates to the client app with minimal overhead."),
        quiz("del-7","How do you handle driver location tracking at scale (e.g., 500,000 drivers updating GPS every 3 seconds)?","hard",("case-study",),
             ("Enforce clients to poll drivers directly via peer-to-peer web connections", "Route all pings through a distributed consensus group like ZooKeeper to ensure order", "Write all raw location pings directly to a relational database primary write replica", "Buffer location updates in a fast in-memory store like Redis, then periodically persist or drop historical traces"),3,
             "Redis handles hundreds of thousands of writes/sec with ease. Storing temporary coordinate points in memory protects relational DBs."),
        quiz("del-8","What is the role of an Order Matching Engine in a delivery app?","hard",("case-study",),
             ("To run static SQL queries that calculate daily sales tax values", "To match orders with available drivers based on proximity, route efficiency, and wait times", "To encrypt credit card payment information during checkout", "To generate restaurant menu recommendations using deep learning algorithms"),1,
             "The matching engine coordinates complex operations: finding the best driver, projecting route paths, and assigning the task."),
        quiz("del-9","How do you handle 'dual-write' issues where the Order DB and Payment Service must both be updated?","hard",("case-study",),
             ("Use the Outbox Pattern or a Two-Phase Commit (2PC) to guarantee atomic database updates and event publishing", "Avoid updating the database and store transaction records solely in the gateway cache", "Perform both updates in parallel without error handling, assuming networks are 100% reliable", "Execute database updates only, and rely on users to manually report missing payments"),0,
             "The Outbox pattern writes events to an internal DB table in the same transaction, ensuring reliable publishing to message brokers."),
        quiz("del-10","What is the best way to handle restaurant menu caching?","medium",("case-study",),
             ("Cache menu data with a long TTL (e.g. 24 hours) since menus change infrequently, with explicit invalidation on updates", "Use a write-behind strategy to flush menu changes to the DB after 7 days", "Never cache menus to ensure users always see real-time price updates from the database", "Cache menus on client devices only without server-side backups"),0,
             "Menus are highly static. Caching them reduces load on the primary DB, while an invalidation trigger handles rare changes."),
        quiz("del-11","How can you partition/shard driver location data to scale horizontally?","hard",("case-study",),
             ("Shard location data by city or region code to keep queries local to the region", "Shard data by the driver's unique sequential ID to ensure alphabetical balance", "Shard location data by the timestamp of the GPS update packet", "Store all coordinates in a single monolithic table without partitioning"),0,
             "Queries (e.g., 'find nearby drivers') are strictly localized. Sharding by city keeps geographic data co-located on a single node."),
        quiz("del-12","If a restaurant's order queue grows too long, how should the system handle incoming customer requests?","medium",("case-study",),
             ("Store excess orders in an infinite queue that never returns a response timeout", "Route all excess orders to alternative random restaurants automatically", "Implement back-pressure or show dynamic delivery delay estimates based on restaurant queue depth", "Block customers from opening the restaurant page entirely"),2,
             "Dynamic ETAs and queue warnings adjust client expectations and prevent ordering bottlenecks during peak hours."),
        quiz("del-13","What is the primary trade-off of a short Geohash length (e.g., 4 characters)?","medium",("case-study",),
             ("It is computationally too slow to calculate on modern hardware", "It requires advanced relational database triggers to resolve", "It cannot be cached in Redis memory keys", "It represents a very large area (approx 39km x 20km), containing too many irrelevant restaurants"),3,
             "Short geohashes represent massive regions. Long geohashes represent tiny regions. Proximity searches must balance geohash length."),
        quiz("del-14","What is the purpose of using Dijkstra's or A* algorithm in this system?","easy",("case-study",),
             ("To balance HTTP server load across distributed worker nodes", "To encrypt transaction payloads before routing them to the bank", "To compress coordinate data packets sent to mobile client devices", "To estimate delivery route paths, travel distances, and expected travel times"),3,
             "Graph routing algorithms calculate optimal road network paths rather than simple straight-line 'as-the-crow-flies' distances."),
        quiz("del-15","How do you prevent driver GPS updates from overloading the API gateway?","medium",("case-study",),
             ("Deploy physical load balancers on every delivery vehicle in the fleet", "Use UDP instead of TCP, or implement client-side adaptive throttling based on whether the driver is moving", "Block all updates while the driver is driving at speeds over 10 mph", "Enforce the driver's phone to reboot every 15 minutes to clear network buffers"),1,
             "If driver is stationary, throttle updates (e.g., every 30s). When moving, increase updates. Saves server load and client battery."),
        quiz("del-16","Which database is best for storing historical order details for long-term tax and accounting reports?","medium",("case-study",),
             ("A local SQLite instance stored on the restaurant's tablets", "An in-memory Redis cache with high-frequency snapshotting", "A graph database specialized in relationship mapping", "An OLAP column-store database (like ClickHouse or Snowflake) for massive aggregations and analytics"),3,
             "OLAP databases are highly optimized for fast aggregation queries over billions of historical records."),
        quiz("del-17","How should the order dispatch system react if a driver loses cell connection mid-delivery?","hard",("case-study",),
             ("Immediately cancel the order and issue a full refund to the customer", "Delete the driver's history and ban their device from the platform", "Block all other deliveries in the system until the driver reconnects", "Detect missing heartbeats, temporarily flag driver as offline, and trigger fallback assignment if necessary"),3,
             "Heartbeat detection allows the matching engine to flag inactive drivers and safely re-route orders without leaving customers stranded."),
        quiz("del-18","What is the benefit of a Saga pattern in a local delivery architecture?","hard",("case-study",),
             ("It coordinates multi-service transactions (Order -> Payment -> Restaurant Accept) with compensating transactions on failure", "It secures customer passwords using distributed hashing protocols", "It accelerates local SSD read performance during database migrations", "It automatically scales web socket connections based on system CPU load"),0,
             "A Saga is a sequence of local transactions. If one step fails (e.g. restaurant rejects), Saga executes rollback/compensation steps."),
        quiz("del-19","How does Yelp/DoorDash handle geohash boundary issues (where a restaurant is just across the border of a geohash box)?","hard",("case-study",),
             ("By querying the target geohash AND its 8 adjacent neighbor geohash boxes",
              "By shifting coordinates dynamically until they land in the center of the geohash",
              "By blocking users from searching within 100 meters of quadrant boundaries",
              "By scaling the geohash box dynamically until it contains at least 50 results"),0,
             "Border issues are resolved by fetching the target box plus its 8 surrounding neighbors, ensuring no nearby restaurant is missed."),
        quiz("del-20","What type of index is highly optimized for geospatial operations in PostgreSQL?","medium",("case-study",),
             ("GiST indexes using the PostGIS extension", "Hash indexes designed for rapid exact-match coordinate pairs", "Inverted GIN indexes built on JSON coordinate arrays", "Standard BTREE indexes on coordinate columns"),0,
             "PostgreSQL with PostGIS uses GiST (Generalized Search Tree) indexes to accelerate geometric/geospatial queries."),
    ))

def news_aggregator_lesson() -> Lesson:
    return Lesson(id="hld-news-aggregator", number=203, title="News Aggregator",
        focus=("ranking algorithm","read-heavy","caching","crawler integration","feed generation"),
        overview="Design a scalable news aggregator like Hacker News or Reddit with dynamic ranking.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("new-1","How does Hacker News rank stories to keep the front page fresh?","medium",("case-study",),
             ("Stories are ordered strictly chronologically by upload timestamp", "Rank is based on the length of the article's text content", "Rank is randomized to ensure equal exposure for all submissions", "Rank is proportional to votes divided by time elapsed raised to a gravity exponent"),3,
             "Hacker News uses: Score = (Votes - 1) / (Age + 2)^gravity. Gravity (typically 1.8) penalizes older stories over time."),
        quiz("new-2","What is a major challenge of a dynamic ranking formula (e.g. votes/time) for database queries?","hard",("case-study",),
             ("Older records must be deleted constantly to prevent query compilation errors", "Relational databases cannot perform division or exponent operations", "Sorting by formula requires exclusive tables locks on every read", "Rank changes constantly with time, making it impossible to use database indexes to sort results efficiently"),3,
             "Since 'Age' increases continuously, index values change constantly. Querying directly would require a full table scan and sort on every load."),
        quiz("new-3","How do you scale front-page reads for a highly popular news aggregator?","medium",("case-study",),
             ("Run a distributed lock across the entire website cluster on every single vote", "Pre-compute and cache the top 100 ranked stories in memory, updating the cache periodically (e.g. every 1-5 minutes)", "Force every user's browser to execute full table scans directly on the master database", "Store all articles as plain text files in a shared network drive"),1,
             "Caching the pre-computed front page serves 99.9% of traffic from fast memory, protecting the DB from raw read loads."),
        quiz("new-4","How should user vote writes be scaled to handle traffic spikes (e.g. viral breaking news)?","hard",("case-study",),
             ("Limit users to casting one vote every 24 hours to protect database capacity", "Write votes to a fast messaging queue (like Kafka) or in-memory buffer (Redis) to batch and update DB asynchronously", "Force every write to execute a synchronous multi-table join transaction", "Convert all votes into JSON files uploaded directly to CDN edge zones"),1,
             "Asynchronous write-behind buffering protects databases from lock contention and write volume spikes on hot articles."),
        quiz("new-5","What is the best way to handle comment thread trees in relational databases?","hard",("case-study",),
             ("Store all comments flat and sort them alphabetically in the application layer", "Re-index the entire database table every time a user posts a comment", "Run N recursive SQL queries, one for each comment layer, on every thread render", "Use materialized paths (e.g. path '0001/0002/0005') or nested sets to fetch comment hierarchies in one clean query"),3,
             "Materialized paths allow rapid, single-query retrieval of entire deeply-nested comment structures with simple parent-child ordering."),
        quiz("new-6","How does Reddit's Hot ranking algorithm handle comment voting compared to Hacker News?","hard",("case-study",),
             ("Reddit ranks posts strictly by user comment count, ignoring upvote counts", "Reddit stores all votes in a centralized global thread lock", "Reddit randomizes rankings for users who are not logged in", "Reddit uses logarithmic scaling for early votes and adds a physical time-decay factor directly to the score"),3,
             "Reddit's algorithm uses log scale: first 10 votes have same impact as next 100, and timestamp score ensures older posts decay rapidly."),
        quiz("new-7","What caching strategy is best for personalizing feed items (e.g. hiding clicked/read links per user)?","hard",("case-study",),
             ("Encrypt the read history and store it as a single string inside the front-page CDN", "Download the entire site database to the user's browser memory for local filtering", "Store each user's read history in a fast Redis Bitmap or Set, and filter the cached front-page list in application memory", "Create a customized, non-cached database view for every single visitor session"),2,
             "Checking viewed items against a fast in-memory Bitmap/Set (O(1)) allows personalizing cached feeds with extremely low latency."),
        quiz("new-8","How do you implement search functionality across millions of submitted articles?","medium",("case-study",),
             ("Write search queries to local client cookies and execute scans in JavaScript", "Deploy an Elasticsearch cluster to index titles, descriptions, and comments for full-text search", "Create a single massive B-tree index covering every column in the table", "Run raw SQL 'LIKE %query%' queries on every user search request"),1,
             "Elasticsearch provides fast, scalable full-text indexing, relevance ranking, and fuzzy matching that relational DBs cannot handle efficiently."),
        quiz("new-9","What is the role of the Web Crawler in a news aggregator?","medium",("case-study",),
             ("To monitor the local database for missing indexes", "To balance traffic across active backend web servers", "To encrypt user session payloads during login transactions", "To scrape destination articles to generate titles, summaries, and preview images automatically"),3,
             "Crawlers fetch target links asynchronously, parsing metadata (OpenGraph tags) to populate rich link previews on the platform."),
        quiz("new-10","How can you handle duplicate article submissions (same link posted multiple times)?","medium",("case-study",),
             ("Allow all duplicates and let the voting system filter them out naturally over time", "Convert duplicate URLs to Base58 and store them in separate sharded tables", "Physically modify the destination server to block external referrals", "Store the canonical URL hash as a unique index key in the database and reject duplicate writes"),3,
             "A unique index on the normalized URL hash (e.g. SHA-256) cleanly prevents duplicate submissions at the database layer."),
        quiz("new-11","Why shouldn't you update the post score in the DB on every single page view?","easy",("case-study",),
             ("Relational databases cannot update integer values concurrently", "Database transactions are disabled during HTTP GET requests", "Page views cannot be counted due to browser privacy policies", "It creates massive write locks on the post record, killing read performance for popular posts"),3,
             "High-frequency writes on a single database row (hotspotting) degrade database performance. Views should be buffered or batched."),
        quiz("new-12","What is a write-behind strategy for page views?","medium",("case-study",),
             ("Enforce clients to write directly to a local filesystem log file", "Write the page view to a backup database after 30 days of inactivity", "Increment view counts in Redis (INCR) and flush to the relational database in batches every few minutes", "Reject page views from anonymous users to minimize database transactions"),2,
             "Using Redis as an in-memory counter with periodic database flushing absorbs massive traffic peaks with ease."),
        quiz("new-13","What is the disadvantage of pre-computing feeds for all users in a news aggregator?","hard",("case-study",),
             ("User feeds must be encrypted with separate unique keys, bloating memory footprints", "Inactive users waste storage and CPU resources, causing massive compute overhead for zero value", "It prevents users from searching historical article lists", "Pre-computation is incompatible with mobile device screen resolutions"),1,
             "Hybrid approach: pre-compute feeds only for highly active users (push model); compute dynamically on login for inactive users (pull model)."),
        quiz("new-14","How does a news aggregator scale during global breaking events (e.g. 100x traffic spike)?","medium",("case-study",),
             ("Route all traffic through a single queue that processes requests one at a time", "Disable CSS and Javascript styling to reduce network traffic", "Spin up larger single database master servers vertically", "Serve static, fully cached HTML pages from global CDN edge networks, bypassing application servers completely"),3,
             "Serving static cache directly from CDNs handles millions of hits with near-zero origin server involvement."),
        quiz("new-15","What is the benefit of using a NoSQL Document Store (like MongoDB) for article comments?","hard",("case-study",),
             ("Document stores natively support ACID transactions across multiple unrelated tables", "NoSQL databases automatically prevent duplicate comments through hardware-level validation", "It eliminates the need for any server-side validation logic", "You can store the entire comment tree as a single nested JSON document, avoiding multi-table joins on retrieval"),3,
             "Document stores match the nested structure of comment threads naturally, enabling single-document reads for entire branches."),
        quiz("new-16","What is the risk of keeping the entire article comment hierarchy in a single document in MongoDB?","hard",("case-study",),
             ("Documents have a hard size limit (e.g., 16MB in MongoDB), which viral posts with thousands of comments will exceed", "Only one user can read a single document at a time due to exclusive locks", "Nested structures cannot be read by modern web browsers", "It forces all comments to be written in a single chronological order"),0,
             "The 16MB limit requires careful design: break comments into paginated buckets or individual documents with parent pointers instead."),
        quiz("new-17","How do you implement spam detection for rapid article submissions?","medium",("case-study",),
             ("Encrypt user browser headers to detect unauthorized proxy networks", "Block all users who write more than two words in their article titles", "Use a Token Bucket or Leaky Bucket rate limiter per user IP and account age tier", "Require manual administrator approval for every submitted URL link"),2,
             "Rate limiters protect the system from automated bots, script spammers, and API abuse."),
        quiz("new-18","What is the primary trade-off of a push vs pull delivery model for news feeds?","hard",("case-study",),
             ("Push saves read latency but wastes write resources; pull saves write capacity but adds query latency on reads", "Push requires symmetric encryption keys; pull operates over unencrypted channels", "Push works only on iOS devices; pull is designed exclusively for Android systems", "Push is for small text files; pull is for large multimedia blobs"),0,
             "Push models write updates directly to follower tables. Pull models query all followed creators dynamically at request time."),
        quiz("new-19","How do you prevent 'vote ring' manipulation in a news aggregator?","medium",("case-study",),
             ("Disable voting for all users who registered within the last 12 months", "Log and analyze vote patterns asynchronously via anomaly detection models (IP tracking, account age, vote co-occurrence)", "Verify every vote by sending a text message confirmation code to the user", "Store all votes in a public spreadsheet accessible by all members"),1,
             "Asynchronous batch analysis tracks voting networks and anomalies without adding latency to the client's vote path."),
        quiz("new-20","What index is highly recommended for sorting articles by score and timestamp?","hard",("case-study",),
             ("A partial index on the user ID field", "A hash index covering the article title", "A composite index on (score, created_at)", "A GIN index mapping text content words"),2,
             "Composite indexes allow the database engine to locate, filter, and sort rows rapidly without scanning the entire table."),
    ))

def ticketmaster_lesson() -> Lesson:
    return Lesson(id="hld-ticketmaster", number=204, title="Ticketmaster",
        focus=("concurrency","transaction isolation","distributed lock","seat holding","caching"),
        overview="Design a ticket booking system like Ticketmaster handling high-concurrency seat reservation.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("tkt-1","How does Ticketmaster handle seat lock reservations (e.g. holding seats for 10 minutes)?","medium",("case-study",),
             ("By creating a seat reservation record with a timestamp, marked as 'HOLD', and releasing it if not paid within 10 minutes", "By locking the entire database table during the checkout process", "By updating the client's browser session variable and assuming the client will release the lock on timeout", "By deleting the seat row entirely and recreating it after payment completes"),0,
             "A state-based reservation holding mechanism with a TTL (e.g. database timestamp check) prevents double-booking while ensuring seats release."),
        quiz("tkt-2","Which transaction isolation level is required to guarantee no two users can book the same seat simultaneously?","hard",("case-study",),
             ("Repeatable Read", "Read Uncommitted", "Read Committed", "Serializable (or explicit SELECT ... FOR UPDATE pessimistic locking)"),3,
             "Serializable prevents write skew and phantom reads. Pessimistic locks (FOR UPDATE) block other readers from acquiring the same seat row."),
        quiz("tkt-3","What is the role of a distributed lock (e.g. Redis Redlock) in Ticketmaster?","hard",("case-study",),
             ("To prevent concurrent bookings for highly hot events at the application layer before hitting the database", "To balance network traffic across distributed global CDN edge nodes", "To manage user session logs across active server clusters", "To encrypt transaction payloads during credit card processing"),0,
             "Distributed locks coordinate multiple stateless application servers, rejecting duplicate concurrent reservation attempts at the gates."),
        quiz("tkt-4","How does Ticketmaster handle extreme traffic spikes when a popular concert goes on sale?","medium",("case-study",),
             ("By using a virtual waiting room queue (e.g., Queue-it) to throttle incoming users and rate-limit checkout traffic", "By caching the checkout write API endpoint globally on CDNs", "By scaling relational database write instances to 1,000 nodes vertically", "By allowing double bookings and sorting out seats manually later"),0,
             "Waiting rooms decouple high user volume from transaction backends, allowing only N users per minute into the ticket checkout funnel."),
        quiz("tkt-5","Why is an optimistic lock (version column) not ideal for highly contested seats?","hard",("case-study",),
             ("Optimistic locking does not work with relational databases", "Optimistic locking requires double the memory capacity of pessimistic locking", "It causes high failure rates and excessive retries for users when many try to lock the same popular seats simultaneously", "It forces all seat records to be deleted on update failure"),2,
             "Under high contention, optimistic locks fail frequently, causing frustrating transaction aborts for users. Pessimistic locking is cleaner here."),
        quiz("tkt-6","What database schema pattern is best for matching seats to bookings?","medium",("case-study",),
             ("A NoSQL Key-Value store where the key is user_id and the value is a list of seat numbers", "A single massive text file containing all reserved seat names", "A relational table with columns: booking_id, seat_id, show_id, status, locked_until", "A graph database mapping ticket brokers to event coordinators"),2,
             "Relational schemas with unique constraints (e.g. unique constraint on show_id + seat_id) prevent duplicate bookings structurally."),
        quiz("tkt-7","How can you partition/shard the Ticketmaster database to handle global scale?","hard",("case-study",),
             ("Shard data dynamically based on the timestamp of the ticket purchase", "Shard data by User ID to ensure even write distribution across all servers", "Shard data by Event ID, so all seating and transaction records for a specific concert are co-located on one partition", "Store all global ticket records in a single partition sorted alphabetically by city"),2,
             "A concert's transaction boundaries are self-contained. Sharding by Event ID ensures local transactions and avoids cross-partition queries."),
        quiz("tkt-8","What is the danger of sharding by Event ID for highly popular events (e.g. Taylor Swift)?","hard",("case-study",),
             ("It creates a severe hot shard where one physical database node receives 99% of the global traffic", "It disables index lookups for secondary column fields", "It prevents users from purchasing tickets to multiple different events", "It makes it impossible to run backups on the event table"),0,
             "A hot event will overwhelm the single shard storing it. Mitigation: allocate a dedicated replica pool or use a queue for hot events."),
        quiz("tkt-9","What happens if the primary database node crashes mid-transaction during a ticket booking?","hard",("case-study",),
             ("The transaction is permanently lost and the seat remains locked forever", "The client's web browser automatically resolves the database transaction state", "The system automatically reverts to offline physical paper ticket sales", "The standby replica promoted to leader must have transactional WAL records replicated synchronously to prevent double sales"),3,
             "Synchronous replication of write-ahead logs (WAL) ensures zero data loss during failover, avoiding dual seat assignments."),
        quiz("tkt-10","Why are CDN edge caches not suitable for storing real-time seat availability maps?","medium",("case-study",),
             ("Seating availability changes continuously in milliseconds, and serving stale data causes users to try booking taken seats", "Symmetric encryption protocols cannot be deployed on CDN servers", "CDN caching is restricted to text documents under 1KB in size", "CDNs do not support image files representing seat layouts"),0,
             "Stale seating maps cause extreme user frustration. Seat availability should be fetched dynamically or pushed via lightweight streams."),
        quiz("tkt-11","How can we optimize seat map rendering for thousands of concurrent users?","medium",("case-study",),
             ("Send the complete coordinate database of all stadium seats to the client device", "Avoid rendering visual maps and show simple text lists instead", "Generate a static SVG/JSON layout stored on a CDN, and fetch real-time availability states via a fast lightweight API", "Render the entire seating map dynamically from raw database tables on every page reload"),2,
             "Static asset delivery from CDNs keeps servers cool, while lightweight dynamic pings overlay live seat states on the client UI."),
        quiz("tkt-12","What is the role of an asynchronous worker pool in Ticketmaster?","medium",("case-study",),
             ("To balance HTTP gateway requests across active web servers", "To encrypt credit card details inside the user's browser", "To process payment confirmation, generate email receipts, and update analytics reports off the hot write path", "To run real-time transaction validations during database lock phases"),2,
             "Asynchronous processing removes slow downstream workflows (email, tickets PDF generation) from the critical transaction path."),
        quiz("tkt-13","Which payment handling pattern ensures customers are not charged if the database transaction fails?","hard",("case-study",),
             ("Two-Phase commit or reservation-first pattern: lock the seat first, process payment, then commit the booking", "Charge the credit card first, and run background cleanup scripts to find seats if charging succeeded", "Avoid using external payment gateways and store credit card numbers directly in the database", "Run payments and database writes in parallel without synchronization"),0,
             "Hold seat -> Charge payment -> Confirm seat. If payment fails, release the seat hold. Protects both merchant and user."),
        quiz("tkt-14","What is the purpose of idempotency keys in Ticketmaster's checkout API?","hard",("case-study",),
             ("To encrypt transaction payloads during transport layer security (TLS) handshakes", "To prevent duplicate ticket bookings if a user double-clicks the 'Submit' button or retries a failed network call", "To verify the physical location of the ticket buyer's IP address", "To index seat columns inside the relational database"),1,
             "An idempotency key (e.g. UUID) ensures the checkout pipeline processes a specific booking request exactly once, returning cached response on retries."),
        quiz("tkt-15","How should the system handle a seat reservation timeout?","medium",("case-study",),
             ("Immediately delete the user's account and ban their IP address", "Overwrite the seat table with the last full system backup file", "Force the database to restart to release active page locks", "Run a background worker that regularly checks for expired holds (locked_until < NOW()) and marks them back as 'AVAILABLE'"),3,
             "An active janitor service or database TTL cleans up expired holds, returning unpaid seats back to the general inventory pool."),
        quiz("tkt-16","What is the benefit of a database lock escalation warning in this scenario?","hard",("case-study",),
             ("It alerts the client browser to compress all outgoing checkout requests", "It signals the API gateway to increase rate limits automatically", "Relational databases may escalate row locks to page/table locks under massive writes, locking the entire venue", "It indicates that the database requires a physical hardware restart"),2,
             "If too many rows in the seat table are locked, the DB might lock the whole table, paralyzing booking. Keep transactions fast and granular."),
        quiz("tkt-17","What is the advantage of sharding seat tables by Event ID over venue location?","medium",("case-study",),
             ("Event IDs are always represented as smaller data types than venue names", "Venue-sharded databases cannot enforce primary key constraints", "Event-sharded partitions automatically run on SSD storage arrays", "Events are self-contained logical partitions; sharding by venue causes multi-event overlaps and cross-shard queries"),3,
             "An event happens at a specific time. Venue sharding would group past/future unrelated shows, whereas Event sharding cleanly splits the load."),
        quiz("tkt-18","How does Ticketmaster prevent bots from buying up all available tickets within seconds?","medium",("case-study",),
             ("By deploying advanced bot mitigation systems (e.g. Cloudflare Bot Management, CAPTCHAs, and restrictive rate-limiters)", "By blocking all users who purchase more than two tickets in a 12-month period", "By requiring physical mail confirmation before releasing tickets", "By storing all ticket inventory in encrypted databases that only allow manual decryptions"),0,
             "Bot detection analyses traffic patterns, mouse behaviors, and reputation scores to reject automated scaling scripts."),
        quiz("tkt-19","What is the primary drawback of using a Distributed Lock Manager (DLM) like Redis Redlock for every seat?","hard",("case-study",),
             ("It adds network overhead and complexity, creating a dependency that can impact reliability if the Redis cluster fails",
              "Redlock cannot handle more than 10 concurrent locks globally",
              "It requires physical hardware changes to the database storage layer",
              "It only supports locking of integer columns, not string representations"),0,
             "DLMs add significant network steps. If not carefully designed, they create hard single-points-of-failure or slow down the booking path."),
        quiz("tkt-20","What type of index should be placed on the seat reservation table to optimize status checking?","hard",("case-study",),
             ("A single hash index on the customer's email address column", "A clustered index sorting all records alphabetically by venue location", "A composite index on (show_id, status) or partial index filtering where status='HOLD'", "A GIN index covering the transaction detail JSON payload"),2,
             "A composite index on (show_id, status) allows the database to instantly locate available or locked seats for a specific event."),
    ))

def fb_news_feed_lesson() -> Lesson:
    return Lesson(id="hld-fb-news-feed", number=205, title="FB News Feed",
        focus=("fanout on read","fanout on write","feed cache","timeline service","hybrid model"),
        overview="Design a highly scalable, real-time news feed system like Facebook or Twitter.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("fnf-1","What is Fan-out on Write (Push model) in news feed design?","medium",("case-study",),
             ("Writing the post data directly to all physical databases globally in parallel", "Pulling posts from all followed creators dynamically when the user requests their feed", "Writing a new post directly to the feed caches of all the creator's followers", "Compressing feed items into a single zip file before saving them to disk"),2,
             "Fan-out on write pre-computes feeds: when a post is created, it's pushed to every follower's in-memory timeline inbox."),
        quiz("fnf-2","What is Fan-out on Read (Pull model) in news feed design?","medium",("case-study",),
             ("Fetching posts from all followed accounts and sorting them on-the-fly when the user loads their feed", "Pushing a new post to all followers' feeds synchronously at creation time", "Caching all historical post content on the client's local smartphone storage", "Reading all database records sequentially to identify duplicate user profiles"),0,
             "Fan-out on read queries followed users dynamically. Slow on reads, but avoids massive write overhead during creation."),
        quiz("fnf-3","Why is a pure Fan-out on Write (Push) model bad for 'celebrity' accounts (e.g. millions of followers)?","hard",("case-study",),
             ("Celebrity posts require custom cryptographic signatures that cannot be computed fast", "A celebrity post triggers millions of database writes simultaneously, overwhelming the feed cache cluster (hotkey/write spike)", "Followers of celebrities are highly distributed and cannot access the same cache servers", "Relational databases cannot partition tables representing celebrity user IDs"),1,
             "A celebrity with 100M followers posting triggers 100M write operations. This is the classic 'celebrity problem' or 'hotspotting'."),
        quiz("fnf-4","How does a hybrid feed architecture resolve the celebrity problem?","hard",("case-study",),
             ("Use Push for normal users, and dynamically pull (merge) celebrity posts when a follower loads their feed", "Store celebrity posts in a separate relational database that uses vertical scaling only", "Force all users to use the pull model during peak hours, and push only during low traffic", "Convert all celebrity feeds into static PDF files distributed via CDN"),0,
             "Hybrid: pre-compute feeds from regular users (push). When rendering, query celebrity posts dynamically (pull) and merge them."),
        quiz("fnf-5","Which technology is best suited for storing and serving pre-computed news feeds?","medium",("case-study",),
             ("An in-memory store like Redis, representing timelines as Sorted Sets (ZSET) ordered by timestamp", "An append-only log file stored on a shared network drive", "A distributed graph database containing all historical post comments", "A relational database with complex multi-table JOINs on every page load"),0,
             "Redis Sorted Sets keep timelines pre-sorted by post ID/timestamp. Fetching a page is a fast O(log N + M) memory operation."),
        quiz("fnf-6","How do you limit the storage footprint of pre-computed feeds in Redis?","medium",("case-study",),
             ("Compress all text characters into binary representations using Huffman coding", "Store only the user's primary key in Redis and fetch everything else from relational tables", "Only cache the feed timeline for active users (e.g., accessed in the last 30 days) and cap feed sizes (e.g., max 500 items)", "Delete all user posts that are older than 24 hours automatically"),2,
             "Capping the timeline size (e.g., top 500 items) and evicting inactive users prevents memory bloat while preserving fast read speeds."),
        quiz("fnf-7","What is the role of the Fan-out Service in a news feed pipeline?","medium",("case-study",),
             ("To consume post events from a message queue and distribute them to followers' timelines asynchronously",
              "To encrypt post content before it is written to the database",
              "To parse post text for full-text search indexing in Elasticsearch",
              "To balance HTTP requests across the frontend web servers"),0,
             "The fan-out service runs in the background (off the main write path), ensuring post distribution does not slow down the creator's post confirmation."),
        quiz("fnf-8","How should post media assets (photos, videos) be delivered to feed readers?","easy",("case-study",),
             ("Avoid using images and restrict the feed strictly to text characters", "Store raw image bytes in the relational database rows and fetch them on every load", "Store files in cloud object storage (e.g. S3) and serve them globally via a Content Delivery Network (CDN)", "Force clients to download media files directly from other online users' devices"),2,
             "Static assets are cached and delivered from CDN edge locations near the user, drastically reducing latency and server loads."),
        quiz("fnf-9","What is a feed ranking/relevance engine, and where does it sit?","hard",("case-study",),
             ("A database trigger that automatically sorts rows inside the relational primary partition", "A load balancer algorithm that distributes reads based on server CPU load", "A client-side script running inside the user's web browser framework", "A machine learning pipeline that ranks posts dynamically, sitting between the timeline cache and the feed API"),3,
             "The ranking engine scores posts based on user interests, interactions, and age, creating a highly customized timeline."),
        quiz("fnf-10","Why is standard relational database pagination (OFFSET) bad for infinite scroll feeds?","hard",("case-study",),
             ("It locks the entire database table during query execution", "If new posts are added at the top, the window shifts, causing duplicate or skipped items on subsequent pages", "OFFSET forces the client browser to reload all CSS styling files", "Relational databases do not support page-based offset SQL statements"),1,
             "New posts shift row indices. Use cursor-based pagination (e.g. WHERE id < last_seen_id LIMIT 10) for stable feeds."),
        quiz("fnf-11","How do you handle feed generation if a user follows 50,000 accounts?","hard",("case-study",),
             ("Fallback to a pull-based merge model using distributed MapReduce queries over highly indexed post databases", "Block the user from following more than 1,000 accounts to protect cache memory", "Store all 50,000 feeds in a single local browser cookie payload", "Force all 50,000 creators to write directly to a single shared database row"),0,
             "Users following huge numbers of accounts mimic the celebrity problem in reverse. Pull-based lazy merging is much safer here."),
        quiz("fnf-12","What is the purpose of the Feed Generation Service in the background?","medium",("case-study",),
             ("To run security scans across user profile images", "To encrypt all database tables using AES-256 protocols", "To pre-generate feeds for highly active users during low-traffic hours so they are immediately available on login", "To manage DNS record propagation times globally"),2,
             "Pre-generation (cache warming) ensures active users experience zero-latency loads when they open the application."),
        quiz("fnf-13","Which cache pattern is most appropriate for post content (the actual text, author, likes count)?","medium",("case-study",),
             ("Cache-aside with a distributed Redis key-value store, where key is post_id", "No caching; read post content directly from the DB on every timeline render", "Store all post content inside the user's profile metadata row", "Write-behind with a single local SSD storage array"),0,
             "Timelines store list of post IDs. Actual post content is fetched from a fast post cache (cache-aside) using batch lookups."),
        quiz("fnf-14","How do you ensure high availability for feed reads?","medium",("case-study",),
             ("By deleting old posts to reduce the size of the active read index", "By enforcing all read requests to route through a single master database node", "By blocking writes to the feed cache during read operations", "By replicating the feed cache across multiple geographic regions with local edge servers"),3,
             "Geographic replication handles local disasters, reduces cross-continent latency, and ensures near-100% read availability."),
        quiz("fnf-15","What is the role of a Message Queue (e.g., Kafka) in the feed writing pipeline?","medium",("case-study",),
             ("To store historical post comments for fast lookup search indexes", "To encrypt message packets before transmitting them to databases", "To buffer newly created posts and decouple the write API from the asynchronous fan-out worker pool", "To balance HTTP connections across frontend reverse proxies"),2,
             "Kafka absorbs write spikes, guarantees message delivery, and allows fan-out workers to process distribution lists at their own pace."),
        quiz("fnf-16","What is the best way to handle real-time feed updates (e.g. 'New Posts' notification bubble)?","medium",("case-study",),
             ("Send a background SMS ping to the user's phone on every new post", "Establish a WebSocket or SSE connection from client to server to push notifications when a new post is fanned-out", "Scan the relational database constantly using recursive client-side queries", "Force the client browser to refresh the entire page every 5 seconds"),1,
             "Persistent connections allow lightweight push alerts, giving the user control to click and load new items without disrupting current reading."),
        quiz("fnf-17","How does the system ensure feed security (blocking posts from private accounts you don't follow)?","hard",("case-study",),
             ("Store private posts in separate physical databases located in different countries", "Encrypt posts from private accounts with a master key that is blocked by local client firewalls", "Enforce strict permission checks in the Feed API layer, validating relationships in a fast graph cache before rendering", "Allow all posts in the feed but obscure the text using CSS styling for unauthorized users"),2,
             "Timelines can get stale. A final security filter at the API layer ensures no private content leaks if relationship statuses change."),
        quiz("fnf-18","What is the primary trade-off of storing pre-computed feeds in Redis vs a NoSQL Document Store?","medium",("case-study",),
             ("Redis provides ultra-low latency in RAM but is highly expensive; Document stores are cheaper (disk-based) but slower", "Redis only supports text storage; Document stores can store raw binary video files natively", "Redis requires custom database hardware; Document stores run on standard cloud VMs", "Redis is strongly consistent; Document stores are always eventually consistent"),0,
             "RAM storage (Redis) is fast but costly. Storing older feeds or inactive timelines on disk (e.g. Cassandra/Mongo) keeps costs sane."),
        quiz("fnf-19","How should like counts and comment counts be tracked in the feed efficiently?","hard",("case-study",),
             ("Force users to wait for database locks to release before casting a like", "Store counters in a fast in-memory cache (Redis) and periodically batch-update the relational database", "Run a full COUNT(*) query across the entire comments and likes table on every post load", "Write like events to client browser local storage only"),1,
             "Aggregating counts in memory prevents database write bottlenecks on viral posts where thousands of users 'like' simultaneously."),
        quiz("fnf-20","What index optimizes fetching a user's own posts for their personal profile timeline?","easy",("case-study",),
             ("A partial index built only on the posts that contain media assets", "A composite index on (user_id, created_at DESC)", "A single index on the post content text string", "A hash index covering the profile picture URL"),1,
             "Composite index on (user_id, created_at DESC) allows instant, pre-sorted retrieval of a user's history for their profile timeline."),
    ))

def tinder_lesson() -> Lesson:
    return Lesson(id="hld-tinder", number=206, title="Tinder (Matchmaking/Geospatial)",
        focus=("spatial indexing","geohash","bidirectional match","recommendation engine","contention"),
        overview="Design a location-based matchmaking service like Tinder with real-time swipe matching.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("tnd-1","How does Tinder filter potential matches by geographic distance?","medium",("case-study",),
             ("By sharding the user database alphabetically based on their first name", "By calculating the exact distance to all global users using SQL queries on every swipe", "By blocking matches between users who reside in different time zones", "By partitioning users into Geohash grid cells and searching within the user's active geohash and its neighboring cells"),3,
             "Geohash converts 2D coordinates into simple strings. Proximity search is simplified to querying matching string prefixes."),
        quiz("tnd-2","What database indexing strategy accelerates finding active users within a 10-mile radius?","medium",("case-study",),
             ("A standard B-tree index on the user's birthdate column", "Geospatial indexing (e.g., Redis GEO commands, PostgreSQL PostGIS/GiST, or MongoDB 2dsphere)", "A hash index on the coordinate latitude column alone", "Enforcing full table scans with custom client-side distance checks"),1,
             "Geospatial indexes use advanced space-filling curves (like Hilbert or Morton curves) to organize 2D data for fast spatial range queries."),
        quiz("tnd-3","How do you implement the 'Swipe Left' (Reject) flow efficiently at scale?","hard",("case-study",),
             ("Perform a synchronous write lock on both users' accounts in the primary database", "Delete the target user's profile from the database entirely", "Write the rejection event to a fast, eventually consistent write-behind buffer (like Redis or Cassandra) to ignore in future recommendations", "Store the swipe action in the swiping user's local browser cookies"),2,
             "Swipes are write-heavy. Since rejections don't trigger matches, we can write them asynchronously to a cheap, fast NoSQL store."),
        quiz("tnd-4","How does Tinder handle 'Swipe Right' (Like) and detect an instant mutual match?","hard",("case-study",),
             ("Store the like event in a shared global file system log", "Send a push notification to the target user asking them if they like the user back", "Check a fast key-value store (e.g. Redis) if target liked user back -> if yes, trigger match workflow; if no, save the like", "Lock both users' database tables, run a recursive JOIN query, and release locks"),2,
             "A fast O(1) read check in a Redis Set or key-value store (e.g. user_A:likes:user_B) instantly reveals if the target already swiped right."),
        quiz("tnd-5","What is a major challenge of active user matchmaking recommendations?","hard",("case-study",),
             ("Computing the user's profile age comparison using standard SQL commands", "Translating base32 geohashes back into decimal coordinate systems", "Allowing users to upload multiple profile pictures to object storage", "Filtering out users already swiped on (which grows continuously) without running expensive database exclusions"),3,
             "As swiped lists grow to thousands, running SQL 'NOT IN (thousands of IDs)' becomes extremely slow. Mitigation: Bloom filters or fast caches."),
        quiz("tnd-6","How does Tinder handle recommendation feed generation for a user?","hard",("case-study",),
             ("Scan the entire global database of active profiles on every swipe card refresh", "Pre-compute a pool of candidate profiles in the background based on geo-location, age, and preferences, and cache in Redis", "Fetch candidate profiles from a single master database node using nested subqueries", "Generate recommendations dynamically using client-side JavaScript on the user's phone"),1,
             "Pre-computing candidate cards in the background keeps card swiping latency near zero, maximizing user engagement."),
        quiz("tnd-7","What is the benefit of using Redis Geospatial (GEO) for tracking active users?","medium",("case-study",),
             ("It replaces the relational database for user profile and credit card transaction storage", "It uses Sorted Sets under the hood, mapping Geohash values to scores for ultra-fast location range lookups in memory", "It stores user profile pictures as binary blobs in Redis partitions", "It automatically encrypts user location coordinates using AES-256 protocols"),1,
             "Redis GEO commands (like GEORADIUS or GEOSEARCH) leverage base32 geohashes and sorted sets to locate active keys in memory in microseconds."),
        quiz("tnd-8","What is the role of the Recommendation Engine in Tinder?","medium",("case-study",),
             ("To manage user session tokens and enforce API rate-limit security", "To authorize subscription payments through external payment gateways", "To score and rank potential match candidates based on distance, active status, preferences, and internal scoring metrics", "To compress profile image assets stored on distributed CDN networks"),2,
             "The recommendation engine filters active users nearby, eliminates already-swiped accounts, and ranks candidates to maximize match probability."),
        quiz("tnd-9","How should the system react when a user goes offline or travels to a new city?","medium",("case-study",),
             ("Update their coordinate index in the geo-database dynamically, and clear/rebuild their recommendation card cache",
              "Lock their account and require re-authentication from the new IP location",
              "Delete their swipe history to save storage space in the local partition",
              "Force their device to download the entire new city's profile database"),0,
             "Updating geo-coordinates triggers cache invalidation for their feed, pulling fresh candidates from the new geohash quadrants."),
        quiz("tnd-10","Why is sharding Tinder's database by User ID ideal for profile management but challenging for geo-queries?","hard",("case-study",),
             ("User ID sharding distributes data evenly, but geo-queries require fanning out to multiple shards (scatter-gather) to find nearby users", "Geospatial coordinates cannot be stored in user-sharded relational databases", "User ID sharding prevents the enforcement of primary key constraints", "It forces all user profile updates to hit a single master database replica"),0,
             "A 'find nearby' query must search across multiple user shards. Solve this by maintaining a separate, dedicated geo-index (e.g. in Redis)."),
        quiz("tnd-11","How can you prevent a race condition where two users match, but the match is written twice?","hard",("case-study",),
             ("Require both users' devices to execute a distributed consensus protocol (like Raft) before swiping", "Store the match record only in temporary in-memory caches that expire in 24 hours", "Enforce a strict alphabetical sorting key for matches (e.g. match_id = min(A,B) + '_' + max(A,B)) with a unique constraint", "Delete both swipe history profiles from the database and recreate them as a matched pair"),2,
             "Ordering user IDs alphabetically ensures that no matter who swipes second, the system attempts to write to the exact same unique key, preventing duplicate records."),
        quiz("tnd-12","What is the best way to deliver chat messages between two matched users?","medium",("case-study",),
             ("Establish active WebSocket connections from both devices to a Chat/Messaging service for instant real-time delivery", "Send messages as SMS notifications through external telco networks", "Write message text directly to a shared relational database table with no caching", "Force devices to poll the database every 100ms via standard HTTP GET queries"),0,
             "WebSockets support low-latency bidirectional streaming, allowing matched users to converse in real-time with minimal server overhead."),
        quiz("tnd-13","Which technology is best suited for storing historical chat messages?","medium",("case-study",),
             ("In-memory Redis caches without database persistence", "An OLAP analytical database (like Snowflake) designed for large aggregations", "A wide-column store (like Cassandra) or NoSQL database (like DynamoDB) sharded by match_id/session_id", "A single monolithic CSV file stored on a shared network drive"),2,
             "Wide-column and key-value stores scale horizontally, handling massive write loads while enabling fast retrieval of chat logs by session ID."),
        quiz("tnd-14","How does Tinder handle profile picture storage and scaling?","easy",("case-study",),
             ("Enforce users to load pictures directly from other active users' phones via P2P networks", "Save raw image binary data directly inside relational database VARCHAR columns", "Compress photos into low-resolution icons that do not require external storage space", "Upload raw images to cloud object storage (e.g., S3), optimize file sizes, and deliver via global CDNs"),3,
             "Object storage + CDNs is the standard architecture for handling media assets globally with low read latency and high availability."),
        quiz("tnd-15","What is the purpose of the 'Active Status' heartbeat in Tinder's matching?","medium",("case-study",),
             ("To prioritize recommending users who are currently online or were active recently, increasing match responsiveness", "To verify subscription billing cards through external bank servers", "To track the user's phone battery level and shut down features when low", "To encrypt API payloads during transport layer security (TLS) handshakes"),0,
             "Recommending active users ensures that if a match occurs, the conversation can start immediately, avoiding dead-account swipe fatigue."),
        quiz("tnd-16","How can we optimize card deck generation for users with very restrictive filters (e.g. 1 year age range)?","hard",("case-study",),
             ("Block them from swiping until they expand their preferences", "Run a full table scan across the entire global profile database", "Ignore their filter settings and show regular candidate pools automatically", "Fallback to direct database geo-queries with strict SQL WHERE filters on indexed age and gender columns"),3,
             "When caches are empty or filters are too narrow, the system falls back to index-driven database queries to ensure accurate results."),
        quiz("tnd-17","What is the benefit of a Bloom filter for swipe history tracking?","hard",("case-study",),
             ("It encrypts user swipe logs before writing them to the transactional database", "It routes user locations to the nearest geographic partition node", "It highly compresses the list of swiped user IDs in memory, allowing instant O(1) checks to filter out already-seen cards", "It automatically resolves database race conditions during matchmaking workflows"),2,
             "Bloom filters have a tiny memory footprint. A user with 10,000 swipes can have their history checked in memory in kilobytes rather than megabytes."),
        quiz("tnd-18","How are matches and chat alerts pushed to offline users?","medium",("case-study",),
             ("By sending daily paper mail digests to their registered home address", "Using Mobile Push Notifications (e.g., Apple APNs or Google FCM) triggered by matching events in the background", "By writing alerts to the client's local browser storage on their computer", "By calling the user's phone number automatically using automated voice messages"),1,
             "APNs and FCM allow servers to wake up offline devices and deliver instant notifications without open WebSocket connections."),
        quiz("tnd-19","What type of locking is most appropriate when updating user profile details?","medium",("case-study",),
             ("Pessimistic locking (SELECT FOR UPDATE) to block all reads during the update phase", "Enforcing a database-wide table lock on the user table", "Optimistic locking (version numbers) since profile updates are infrequent and have very low contention", "Distributed Redlock across all active global application servers"),2,
             "Profiles are rarely updated by multiple actors. Optimistic locking avoids the performance overhead and deadlocks of pessimistic locks."),
        quiz("tnd-20","How does Tinder handle data privacy (e.g. obscuring exact user coordinates)?","medium",("case-study",),
             ("By forcing users to re-verify their location on every single card swipe", "By encrypting coordinate values in the client browser using custom public keys", "By shifting coordinates to a random location in a different country", "By returning distance numbers only (e.g., '3 miles away') and never exposing raw latitude/longitude coordinates to clients"),3,
             "To prevent tracking or stalking, the backend computes distance locally and strips raw GPS coordinates from API payloads returned to clients."),
    ))

def leetcode_lesson() -> Lesson:
    return Lesson(id="hld-leetcode", number=207, title="LeetCode (Online Judge)",
        focus=("sandboxing","job queue","result polling","compilation","idempotency"),
        overview="Design a secure, highly scalable online code execution engine and judge platform like LeetCode.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("ltc-1","How does LeetCode run untrusted user code safely without risking server compromises?","medium",("case-study",),
             ("By running all submissions inside the client's local web browser JavaScript environment", "By requiring users to sign a security waiver before writing code submissions", "By scanning code using regular expressions to block commands containing words like 'rm' or 'sudo'", "By executing code inside secure, isolated sandboxes (e.g., Docker containers, gVisor, or Firecracker microVMs)"),3,
             "Executing user code is highly dangerous. Isolated sandboxes enforce hardware-level or kernel-level boundaries, blocking host system access."),
        quiz("ltc-2","How does LeetCode handle the mismatch between high traffic spikes and slow execution times (e.g., 2 seconds per run)?","hard",("case-study",),
             ("By running all submissions in parallel on a single massive monolithic database master node", "By pushing submissions to a distributed message queue (like RabbitMQ or Kafka) and processing them asynchronously using worker pools", "By caching old submission results and returning them to new users automatically", "By rejecting submissions automatically when active server CPU utilization exceeds 50%"),1,
             "Code execution is slow and resource-heavy. Decoupling the write API from execution via queues prevents web servers from exhausting threads."),
        quiz("ltc-3","How does the user's browser get the execution results in LeetCode's asynchronous architecture?","medium",("case-study",),
             ("The execution workers write results directly to the user's browser cookies", "Client receives a submission_id -> polls a status API (or listens via WebSockets/SSE) until the worker writes results to DB/Cache", "The browser blocks and waits for a single synchronous HTTP connection to keep open for 10 minutes", "The results are emailed to the user as a text attachment"),1,
             "The poll-or-push model ensures web servers remain stateless and free to handle other traffic while background workers execute slow test suites."),
        quiz("ltc-4","How does LeetCode prevent infinite loops in user code from hanging execution workers forever?","medium",("case-study",),
             ("By requiring users to estimate their execution loop boundaries upfront", "By setting strict CPU and wall-clock execution timeouts (e.g., 2 seconds) inside the sandbox environment", "By parsing the code text to count the number of active 'while' or 'for' loops before running", "By manually restarting the physical worker servers every 5 minutes"),1,
             "Enforcing container/process-level timeouts (SIGKILL after N seconds) terminates runaway tasks and frees up worker threads."),
        quiz("ltc-5","What is the role of the Code Builder/Compiler in the execution worker pipeline?","medium",("case-study",),
             ("To pull compile-free or compiled language files, compile them inside the sandbox, and link with hidden test-case drivers", "To index the code variables inside a relational database table", "To manage user session logins and subscription access keys", "To translate Python code into C++ automatically for speed metrics"),0,
             "The builder prepares the environment: it writes the user code and test driver wrapper to a file, compiles if needed, and launches the binary."),
        quiz("ltc-6","How does LeetCode limit memory allocation for user submissions (e.g. Out of Memory limits)?","hard",("case-study",),
             ("By upgrading the physical server hardware whenever an out-of-memory error occurs", "By analyzing the number of array definitions in the code text using regex", "By configuring strict memory limits via cgroups (Control Groups) in the Linux kernel for the sandbox process", "By restricting users to writing code files under 10KB in total size"),2,
             "Linux cgroups regulate resource usage (CPU, Memory, Disk I/O) on a per-process/per-container basis, terminating tasks that exceed limits."),
        quiz("ltc-7","What is the most effective way to store and deliver large test case inputs to workers?","hard",("case-study",),
             ("Retrieve test cases dynamically from other active users' browsers via peer-to-peer streams", "Store test cases as immutable files in S3 and cache them locally on the execution worker SSDs to avoid network latency", "Save test case inputs directly inside relational database VARCHAR columns, fetching them on every run", "Require users to paste the test case inputs directly inside their code files"),1,
             "Test cases are static and can be massive. Caching them locally on worker nodes eliminates S3 network round-trips during hot execution paths."),
        quiz("ltc-8","How are runtime and memory metrics measured accurately in the judge system?","hard",("case-study",),
             ("By estimating complexity based on the number of characters in the user's submission", "By reading process execution metrics directly from the cgroup resource logs and measuring CPU time (not wall-clock time)", "By injecting JavaScript timers (Date.now()) directly into the user's uploaded code string", "By hosting a single benchmark execution node in a separate unvirtualized datacenter"),1,
             "Using cgroup metrics tracks actual CPU-time cycles used by the process, ignoring external host load fluctuations and virtualized delays."),
        quiz("ltc-9","How should LeetCode handle a surge of submissions when a contest begins?","medium",("case-study",),
             ("Disable code compilation and run syntax checkers only", "Route all submissions through a single thread to guarantee chronological ordering", "Directly increase database write locks to block non-contest traffic", "Scale execution worker pools dynamically based on queue depth, and prioritize contest submissions over practice ones"),3,
             "Auto-scaling worker groups handles the demand, while queue priority separation ensures high-stakes contest pings don't get stuck in practice backlogs."),
        quiz("ltc-10","Why is PostgreSQL preferred over Redis for storing historical user submission logs?","medium",("case-study",),
             ("PostgreSQL automatically validates code syntax before storing the record", "Redis is restricted to hosting fewer than 100 total key-value mappings", "Redis does not support string data structures representing code files", "Submission logs are write-once read-rarely, requiring massive, cost-effective relational disk storage with analytical indexes"),3,
             "Redis stores data in RAM, making large historical logs too expensive. Cold, relational disk storage (or cloud data lakes) is far more economical."),
        quiz("ltc-11","What caching strategy optimizes loading the problem page details (title, description, starters)?","easy",("case-study",),
             ("Cache problem details globally on CDNs or in a fast distributed memory cache since they change very rarely", "Query the database primary write replica on every single user view page click", "Force user browsers to store all problem descriptions permanently in their local filesystem", "Write the problem description to a shared file system mounting drive"),0,
             "Static problem data is highly cacheable. Bypassing the database completely handles millions of daily hits with ease."),
        quiz("ltc-12","How do you implement the 'Leaderboard' for contests, showing scores and runtimes of thousands of users in real-time?","hard",("case-study",),
             ("Query and sort the raw submissions table using SQL ORDER BY on every page refresh", "Ask each client browser to fetch all users' scores and calculate the rankings locally", "Store the leaderboard in a flat text file updated manually by cron jobs every hour", "Use a Redis Sorted Set (ZSET) where the key is the contest ID, score is computed from solved counts and penalty times, and value is user_id"),3,
             "Redis ZSETs maintain pre-sorted sets in memory. Fetching leaderboard ranks or ranges (e.g. top 100) is an ultra-fast O(log N) read."),
        quiz("ltc-13","How do you secure the judge system from network-level attacks from within the sandbox?","hard",("case-study",),
             ("Use a public firewall that blocks only known malicious websites", "Require users to supply their network router credentials in the code header", "Disable all network interfaces (no internet access) for the container sandbox process unless specifically required", "Filter code text for URLs containing 'http' or 'https' substrings"),2,
             "Isolating sandboxes from the network (e.g., no default bridge gateway) prevents malicious code from fetching exploits or participating in DDoS attacks."),
        quiz("ltc-14","What type of index optimizes looking up a user's best submission for a specific problem?","hard",("case-study",),
             ("A hash index on the submission text hash", "A GIN index built on the programming language string", "A composite index on (user_id, problem_id, status, runtime)", "A clustered index sorting all submissions by date only"),2,
             "Composite index on (user_id, problem_id) allows the database to immediately locate the subset of rows and evaluate the best status/runtime."),
        quiz("ltc-15","What is the benefit of gVisor over standard Docker containers for LeetCode's sandbox?","hard",("case-study",),
             ("gVisor intercepts system calls and runs a user-space kernel, providing much stronger isolation against container escape exploits", "gVisor compiles Python code directly into native machine assembly", "gVisor automatically scales database write nodes based on execution queues", "gVisor is faster than standard Docker containers because it skips memory allocation steps"),0,
             "Standard Docker containers share the host Linux kernel. gVisor sandboxes system calls, blocking malicious kernel exploits from compromising the host."),
        quiz("ltc-16","How should the system handle duplicate submissions (e.g., user clicking 'Submit' repeatedly)?","medium",("case-study",),
             ("Process every submission fully, spawning separate Docker containers for each double-click", "Force the database to lock the user's entire account profile row for 5 minutes", "Enforce client-side button disabling and use a submit token (idempotency key) in the API layer to reject rapid identical submissions", "Delete the user's historical submissions list on the second duplicate click"),2,
             "Idempotency tokens and gateway rate-limiting prevent duplicate network submissions from overwhelming judge queues and wasting expensive worker cycles."),
        quiz("ltc-17","What is the role of the Test Case Generator in LeetCode?","medium",("case-study",),
             ("To write random test case inputs to the relational database on every submission", "To parse the raw input format and feed test inputs sequentially into the user's compiled executable stdin/arguments", "To verify the user's identity before running execution queues", "To generate graphical visualizations of runtime distributions in JavaScript"),1,
             "The test driver feeds inputs to the sandbox, captures stdout, and compares it against expected outputs to judge correctness."),
        quiz("ltc-18","Which mechanism handles worker node crashes gracefully during execution?","hard",("case-study",),
             ("Force the client browser to detect worker failure and compile the code locally", "Ignore the crash and show the user an eternal 'Pending' state", "Message queues with acknowledgment (ACK) flows — if a worker dies, the un-ACKed submission is automatically returned to the queue", "Reboot the entire active server cluster automatically"),2,
             "Using message acknowledgment guarantees that no task is lost. If a node crashes, the broker detects the closed channel and re-queues the message."),
        quiz("ltc-19","What is the advantage of WebSockets over HTTP short polling for LeetCode's result delivery?","medium",("case-study",),
             ("WebSockets execute code faster because they bypass compile steps", "WebSockets store execution results directly in the client's RAM memory", "WebSockets do not require SSL/TLS encryption protocols", "WebSockets reduce server connection overhead by avoiding repeated HTTP handshakes, header transmission, and DB checks"),3,
             "WebSockets support highly efficient, single-connection real-time push, avoiding the network waste of 10 rapid HTTP polls per user submission."),
        quiz("ltc-20","How does LeetCode calculate the runtime 'Percentile' (e.g. 'Beats 95% of Python3 submissions')?","hard",("case-study",),
             ("Calculate the percentage locally inside the user's browser by comparing with other active users", "Maintain a bucke-based histogram of runtimes per problem per language, and calculate the cumulative distribution asynchronously", "Scan the entire submissions table and run a SQL COUNT query for faster runtimes on every single submission", "Use a random number generator to assign the Beats percentage to keep users motivated"),1,
             "A pre-computed histogram (e.g. tracking counts in 10ms runtime buckets) allows instant calculation of the user's percentile rank without scanning millions of rows."),
    ))

def whatsapp_lesson() -> Lesson:
    return Lesson(id="hld-whatsapp", number=208, title="WhatsApp (Instant Messaging)",
        focus=("gateway connection","session mapping","message queuing","delivery status","group chat"),
        overview="Design a secure, highly scalable instant messaging service like WhatsApp with real-time delivery.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("wa-1","How does WhatsApp maintain persistent real-time connections to millions of active mobile devices?","medium",("case-study",),
             ("By routing all active traffic through a single global proxy server in North America", "By forcing the mobile app to send HTTP POST requests every 200 milliseconds in the background", "By maintaining lightweight, persistent TCP/WebSocket connections (or custom XMPP) managed by a distributed Gateway Service", "By using SMS-based messaging channels for all real-time message notifications"),2,
             "Persistent bidirectional connections allow the server to push messages instantly to the client without the overhead of HTTP polling."),
        quiz("wa-2","What is a major memory constraint of a Gateway (Connection) Server in an instant messaging system?","hard",("case-study",),
             ("Gateway servers cannot store connection state variables in their local RAM", "WebSocket connections consume local storage blocks continuously", "The gateway must download the entire chat history database on startup", "Each open socket requires memory (file descriptors, TCP buffers, thread stack), limiting a single server to ~1M connections"),3,
             "Gateway sizing is memory-bound. Optimization includes reducing OS TCP buffers, increasing file descriptor limits, and using non-blocking I/O (epoll)."),
        quiz("wa-3","Where is the active mapping of User IDs to Gateway Server IPs stored?","hard",("case-study",),
             ("Inside the message payload string itself, sent as a recursive broadcast", "Directly in the client device's local memory parameters", "In a relational database table that is queried on every single message write", "In a fast, distributed in-memory store like Redis (or a consistent-hashing session lookup service)"),3,
             "When User A sends a message to User B, the server must look up B's gateway IP in milliseconds (Redis ZSET/KV) to route the packet."),
        quiz("wa-4","How does WhatsApp handle messages when the recipient is offline?","medium",("case-study",),
             ("Discard the message payload immediately to protect server storage capacity", "Bounce the message back to the sender with a 'Delivery Failed' status code", "Keep the message stored indefinitely in the sender's active gateway thread memory", "Store the message in a transient database (like Cassandra or HBase) and deliver it when the recipient connects (pull/push from queue)"),3,
             "Transient storage buffers offline messages. Once the user connects, the gateway pushes outstanding messages and deletes them from transient tables."),
        quiz("wa-5","What do the 'Single Tick', 'Double Tick', and 'Blue Tick' statuses represent, and how are they tracked?","medium",("case-study",),
             ("Single: Sent to server. Double: Delivered to recipient device. Blue: Read by recipient. Tracked via status update ACK events.", "Single: Draft saved. Double: Checked for spam. Blue: Decrypted by server.", "Single: SMS sent. Double: Email sent. Blue: Push notification successfully shown.", "Single: User online. Double: Writing message. Blue: Message sent successfully."),0,
             "Each status transition triggers a lightweight upstream ACK event (message_id, user_id, status) that updates the sender's UI."),
        quiz("wa-6","Why is End-to-End Encryption (E2EE) highly beneficial for WhatsApp's storage scale?","hard",("case-study",),
             ("E2EE automatically compresses all text messages by 90% before storage", "It prevents the relational database from requiring indexing columns", "E2EE allows the server to bypass SSL/TLS handshake requirements", "Since only clients have keys, the server does not store or process decrypted messages, acting as a simple blind routing pipe"),3,
             "E2EE shifts decryption overhead to clients. The servers only store encrypted byte blobs, removing data compliance and rich processing needs."),
        quiz("wa-7","How does group chat message delivery scale in WhatsApp (e.g. one user sending a message to a group of 500 users)?","hard",("case-study",),
             ("Group chats are stored in a single public CDN edge that is refreshed every 5 seconds", "The sender's device must establish 500 separate WebSocket connections to send the message directly to each member", "The gateway looks up the group roster, duplicates the message for each active member, and routes via their gateways asynchronously", "The server writes 500 identical records to a relational database table before returning success"),2,
             "The server fan-out model handles group routing asynchronously, duplicating the message ID to active member sockets off the sender's write path."),
        quiz("wa-8","Why is Cassandra or DynamoDB ideal for storing instant messaging chat histories?","medium",("case-study",),
             ("They can be hosted inside the client's local smartphone OS environment", "They support high-throughput write streams and support indexing by partition key (chat_id) and clustering key (message_id/time)", "They automatically translate text messages into multiple languages", "They support complex multi-table ACID transactions and JOINs"),1,
             "NoSQL wide-column stores scale writes horizontally with ease. Range queries like 'get last 20 messages for chat_id' are highly optimized."),
        quiz("wa-9","What is a major security challenge when a user registers WhatsApp on a new device?","medium",("case-study",),
             ("Re-indexing the global relational database tables representing user phone numbers", "Encrypting the user's contact list using symmetric master keys", "Validating identity via SMS OTP, generating a new public/private key pair, and verifying keys with active chat groups", "Downloading the entire global chat history database to the new hardware"),2,
             "E2EE requires updating key chains. When a device changes, group members must re-negotiate keys to prevent historical decryption leaks."),
        quiz("wa-10","How can WhatsApp reduce client battery consumption caused by maintaining persistent WebSocket connections?","medium",("case-study",),
             ("By blocking the device's CPU from entering low-power sleep modes", "By routing all network traffic through local Bluetooth sharing arrays", "By forcing the mobile app to run full-screen without screen dimming features", "By using optimized TCP heartbeat intervals (keep-alive) and falling back to OS push notifications when the app is in the background"),3,
             "Dynamic heartbeats adjust to network quality. Backgrounding the app closes the socket; OS push alerts (APNs/FCM) wake the app on new messages."),
        quiz("wa-11","What is a heartbeat (ping/pong) in WebSocket management?","easy",("case-study",),
             ("A database index sweep that runs every 60 seconds", "A metric tracking the physical server CPU core temperature status", "A periodic tiny data packet exchanged between client and server to keep the connection alive and detect silent disconnects", "An encryption protocol key exchange that occurs on every message"),2,
             "Firewalls close idle connections. Regular pings keep sockets open and help the server identify dead connections immediately."),
        quiz("wa-12","How do you handle user profile pictures in WhatsApp efficiently?","medium",("case-study",),
             ("Save raw photo binary structures directly inside relational rows", "Force users to fetch friend pictures directly from other active users' RAM cache", "Upload photos to cloud storage (S3), crop/compress them into multiple resolutions, and deliver via a cached CDN edge", "Obfuscate the image paths using random string transformations"),2,
             "CDNs serve static pictures globally with ultra-low latency, bypassing application and database layers entirely for image reads."),
        quiz("wa-13","What is the role of a Session Manager in a distributed chat application?","hard",("case-study",),
             ("To route HTTP page load requests to the web server cluster", "To track user presence (online/offline status) and active gateway server mappings for all connected clients", "To run full-text search indexing on decrypted user chat archives", "To manage billing profiles and subscription limits for enterprise accounts"),1,
             "The session manager tracks which gateway holds the connection for which user, serving as the central router's compass."),
        quiz("wa-14","How do you handle 'message ordering' across multiple devices in WhatsApp?","hard",("case-study",),
             ("Rely strictly on the physical time of the database master node server clocks", "Sort all messages alphabetically based on the first character of the text content", "Use a hybrid logical clock (HLC) or combination of client-side timestamps and server-sequence numbers inside the database", "Enforce all active global clients to synchronize their system clocks using atomic clocks"),2,
             "Clock drift makes strict physical time ordering unreliable. Sequences or HLCs guarantee causal ordering (message A was sent before B)."),
        quiz("wa-15","What is the benefit of a message delivery queue (like Kafka) inside the chat router?","hard",("case-study",),
             ("It replaces the database for long-term historical chat logs", "It decouples message ingestion from the gateway routing engines, absorbing spikes and ensuring zero message loss", "It encrypts message headers using distributed public key infrastructure", "It automatically compresses the text payload of messages before storage"),1,
             "A message broker provides resilience. If a gateway server becomes hot or crashes, Kafka holds the messages safely until they can be routed."),
        quiz("wa-16","How are group chat membership changes (e.g., adding or removing members) tracked securely?","medium",("case-study",),
             ("By broadcasting roster lists inside every single chat message payload", "In a shared global file system directory containing group list texts", "In a strongly consistent metadata database table, with group versioning to ensure all active clients sync the latest roster", "Inside local client SQLite databases only, without cloud server backup"),2,
             "Group rosters must remain consistent to prevent sending messages to unauthorized users. Relational databases with ACID are standard here."),
        quiz("wa-17","What is the advantage of using local SQLite database storage on the client's phone for WhatsApp?","medium",("case-study",),
             ("It replaces the server-side gateway connection services", "It executes code sandboxing protocols to secure the mobile OS", "It automatically backs up the client's phone data to external cloud drives", "It allows the user to browse their entire chat history instantly offline without hitting the network or paying database costs"),3,
             "Client-side storage keeps the app fast and functional offline, making WhatsApp feel snappy since historical reads are strictly local."),
        quiz("wa-18","How does the WhatsApp media attachment transfer work (e.g. sending a 10MB video)?","hard",("case-study",),
             ("Client streams the raw video binary bytes directly through the active WebSocket connection to the recipient", "Client splits the video into base58 strings sent as separate chat packets", "Client uploads media to media server -> server stores in S3 -> returns asset ID and thumbnail -> client sends asset ID in chat message", "Client uploads video to a relational database table row, locking the table"),2,
             "Streaming large media through WebSockets blocks the connection for text messages. Uploading to S3/CDN is much cleaner and scalable."),
        quiz("wa-19","How do you handle 'Last Seen' presence tracking for millions of active users?","hard",("case-study",),
             ("Ask all followed contacts' phones to query the user's status every 2 seconds", "Batch presence updates in memory and write them to a fast key-value cache (Redis) with write-behind persistence", "Store the last seen timestamp in the user's browser local cookies", "Update a relational database row on every single screen touch or mouse movement"),1,
             "Presence is highly write-intensive. Redis handles these rapid, lightweight updates easily, protecting the persistent DB from write decay."),
        quiz("wa-20","What index optimizes looking up all offline messages for a specific recipient?","hard",("case-study",),
             ("A hash index built on the sender's user ID column", "A single index on the message content text string", "A composite index on (recipient_id, status) where status='OFFLINE'", "A clustered index sorting all messages by creation date globally"),2,
             "A composite index on (recipient_id, status) allows the gateway server to fetch pending offline messages instantly on reconnect."),
    ))

def yelp_lesson() -> Lesson:
    return Lesson(id="hld-yelp", number=209, title="Yelp (Proximity Search)",
        focus=("spatial indexing","geohash","quadtree","sharding by region","read-heavy"),
        overview="Design a local business directory and proximity search service like Yelp or Google Maps.",
        patterns=(), badge="HLD Case Study", tasks=(
        quiz("ylp-1","What is the primary technical challenge of a proximity search query like 'find coffee shops near me'?","medium",("case-study",),
             ("The Earth is spherical, preventing B-tree indexes from ever storing coordinate locations", "Traditional database indexes are 1D, making standard two-column latitude/longitude sorting highly inefficient", "Relational databases cannot perform coordinate arithmetic calculations", "Proximity queries require locking the entire table to prevent concurrent updates"),1,
             "A B-tree on Latitude, and a B-tree on Longitude, cannot be merged efficiently. Spatial indexes solve this 2D search problem."),
        quiz("ylp-2","How does a Geohash group nearby businesses?","medium",("case-study",),
             ("By calculating the alphabetical distance of business names", "By grouping businesses based on their business registration timestamps", "By converting 2D coordinates into a single string; locations close to each other often share the same prefix", "By assigning unique random keys to physical data center locations"),2,
             "Geohash maps a grid system. The prefix represents zoom levels. Finding nearby businesses is simplified to a SQL 'LIKE prefix%' query."),
        quiz("ylp-3","Why are Quadtrees excellent for Yelp's proximity search database?","hard",("case-study",),
             ("They dynamically adapt density: quadrants are recursively split where there are more businesses, keeping lookups fast", "They eliminate the need for memory allocations on database servers", "Quadtrees partition data by the hash of the customer's payment card", "Quadtrees automatically encrypt search strings using AES-256 standards"),0,
             "Quadtrees handle density variations beautifully: sparse country areas remain large boxes; dense downtown blocks split into tiny quadrants."),
        quiz("ylp-4","What is a major trade-off of storing Yelp's business index in an in-memory Quadtree?","hard",("case-study",),
             ("Memory consumption is too high because coordinates require TBs of storage", "Quadtrees are incompatible with standard JSON data structures", "Rebuilding the tree on server restart is slow, and updates require concurrency controls (read-write locks)", "Quadtree search logic is too slow to execute in modern server RAM"),2,
             "To keep reads fast, the tree sits in memory. Modifying it (adding businesses) needs locks, and server crashes require a full reload from the DB."),
        quiz("ylp-5","How should Yelp's database be sharded to scale horizontally?","hard",("case-study",),
             ("Store all coordinates in a single monolithic table with no partitioning", "Shard by Location ID or region code (e.g. City/State), ensuring all local businesses in a region live on the same database node", "Shard by Category ID to keep all restaurants on a single master node", "Shard by Business ID hash to distribute data evenly, fanning out queries to all shards on search"),1,
             "Geography-based sharding maps to yelp queries: searches are 99% local. Storing local data on the same shard avoids slow scatter-gather queries."),
        quiz("ylp-6","What is the benefit of a Google S2 geometry library compared to standard Geohash?","hard",("case-study",),
             ("S2 requires zero memory cache allocation on the server side", "S2 compiles database search queries into native assembly code for faster runtimes", "S2 uses a Hilbert curve to map Earth coordinates to a 64-bit cell ID, offering much smoother boundary and size transitions", "S2 automatically translates business names into local languages"),2,
             "S2 cells are highly precise 64-bit integers with a hierarchy that minimizes border issues and supports arbitrary query shapes."),
        quiz("ylp-7","How is business metadata (reviews, photos, operating hours) best cached in Yelp?","medium",("case-study",),
             ("Cache business records in a write-behind queue that flushes to disk every 30 days", "Cache business profile details in a distributed Redis cache with a long TTL, invalidating on updates", "Store metadata records inside the client browser's local cookies", "Never cache details to prevent showing stale review ratings to customers"),1,
             "Business metadata is read-heavy and static. Caching it protects database read pools, while updates invalidate the cache entry."),
        quiz("ylp-8","How do you scale review writes to handle massive daily volumes without blocking read queries?","hard",("case-study",),
             ("Write review logs to the client's phone filesystem and query P2P", "Disable database index updates for the reviews table", "Use a message queue (like Kafka) to process new reviews asynchronously, updating business aggregate scores off the hot read path", "Enforce strict write locks on the business table for 5 seconds on every review submit"),2,
             "Asynchronous processing decouples reviews from the main business profile view, calculating ratings and updating search indexes in the background."),
        quiz("ylp-9","What is the role of the Photo Processing Service in Yelp's upload pipeline?","medium",("case-study",),
             ("To balance HTTP gateway requests across backend reverse proxies", "To resize, compress, water-mark, and upload photos to S3, updating CDN caching headers", "To verify the user's payment card information", "To index review text keywords for full-text search"),1,
             "Processing media asynchronously optimizes image file sizes and formats for faster delivery to multiple client device classes."),
        quiz("ylp-10","Why is Elasticsearch highly recommended for Yelp's backend search engine?","hard",("case-study",),
             ("Elasticsearch eliminates the need for any cloud object storage servers", "Elasticsearch is a strongly consistent relational database supporting ACID across multi-table joins", "Elasticsearch automatically translates coordinate systems into base32 geohashes", "Elasticsearch natively supports both geospatial filters and complex full-text keyword search queries simultaneously"),3,
             "Elasticsearch combines geo-distance queries with keyword search matching (e.g. 'geo_distance' filter + match 'pizza'), which standard DBs struggle to do efficiently."),
        quiz("ylp-11","What is the boundary issue (edge case) in Geohash proximity searches?","medium",("case-study",),
             ("Geohash strings are too long to fit in standard relational database indexes", "Geohashes do not work at the equator or prime meridian lines", "Two locations can be physically very close but land in different geohash grid cells, having completely different string representations", "Calculating geohashes requires expensive float calculations on every read"),2,
             "Boundary errors occur when points are close but separated by grid borders. Solve by querying the target box plus its 8 surrounding neighbors."),
        quiz("ylp-12","How do you handle 'thundering herd' spikes when a highly popular restaurant page is refreshed frequently?","medium",("case-study",),
             ("Directly increase database write locks to block non-contest traffic", "Route all queries through a single thread to guarantee chronological ordering", "Disable CSS and Javascript styling to reduce network traffic", "Use single-flight cache design to ensure only one database query is executed on a cache miss, while other requests wait"),3,
             "Mutex locks inside the application layer prevent redundant concurrent database calls from executing for the same expired cache key."),
        quiz("ylp-13","What type of database index optimizes sorting restaurants by ratings within a specific city?","hard",("case-study",),
             ("A hash index on the restaurant name string", "A clustered index sorting all records by location coordinates", "A composite index on (city_code, average_rating DESC)", "A GIN index built on the menu array list"),2,
             "Composite index on (city_code, average_rating DESC) allows the database to instantly locate the city's restaurants and return them pre-sorted by rating."),
        quiz("ylp-14","What is the role of an offline batch processing job (e.g. Spark/Hadoop) in Yelp?","medium",("case-study",),
             ("To manage real-time WebSocket connections for chat features", "To handle real-time user authentication and login verification pings", "To encrypt credit card payment details during checkout transactions", "To aggregate and calculate complex search recommendations, ranking scores, and review fraud detection models"),3,
             "Batch analytical engines process massive historical review logs to identify spam rings, aggregate business scores, and warm search indexes."),
        quiz("ylp-15","How can Yelp deliver highly personalized business search results in real-time?","hard",("case-study",),
             ("By forcing the user's device to run scoring algorithms locally in JavaScript", "By storing all personalized search histories in the client's local browser cookies", "By running full database table scans on every keyword search to customize lists", "By applying user profile interests, past check-ins, and search history as ranking features in a fast machine learning scoring layer"),3,
             "A scoring service sits between search retrieval (e.g., Elasticsearch) and the user API, ranking the retrieved candidates using lightweight models."),
        quiz("ylp-16","What is the advantage of using a write-aside or write-behind cache for business reviews count?","hard",("case-study",),
             ("It automatically translates review text into multiple languages", "It prevents users from editing their reviews after submission", "It stores reviews in the client phone's memory to save server storage costs", "It avoids lock contention on the business row by decoupling high-frequency review increments from persistent DB writes"),3,
             "Writing increments asynchronously protects the primary database node from bottlenecking when viral events trigger sudden review bursts on a business."),
        quiz("ylp-17","What is a major limitation of standard relational databases when storing business hours (e.g., open 9am-5pm on Mon, 10am-11pm on Fri)?","medium",("case-study",),
             ("Relational databases can only store date formats, not hourly intervals", "SQL queries automatically crash when processing timezone conversions", "Representing complex, repeating time ranges requires specialized schemas or JSON columns that are hard to query/index in standard SQL", "Relational databases cannot compare time stamps or time ranges"),2,
             "A dedicated table structure (business_id, day_of_week, open_time, close_time) or optimized JSONB schemas in Postgres are required to check 'is open now' efficiently."),
        quiz("ylp-18","How does Yelp handle photo storage and scale high-frequency reads globally?","easy",("case-study",),
             ("Save raw photo binary structures directly inside relational rows", "Force users to fetch friend pictures directly from other active users' RAM cache", "Upload photos to S3 object storage, compress them into multiple resolution options, and deliver via a global CDN edge", "Obfuscate the image paths using random string transformations"),2,
             "Object storage + CDN edge delivery is the industry standard to guarantee fast, scalable, and highly available static asset reads."),
        quiz("ylp-19","What is the benefit of a GIN index on business tags/categories in PostgreSQL?","hard",("case-study",),
             ("It reduces the physical memory storage footprint of the table on disk", "It replaces the database for long-term historical transaction backups", "It automatically encrypts the business category text values", "It allows fast, index-driven lookup of array containment and multi-tag filtering (e.g., find restaurants with tags ['pizza', 'delivery'])"),3,
             "Postgres Generalized Inverted Indexes (GIN) excel at indexing composite structures (arrays, JSONB), enabling direct tag-matching lookups without scans."),
        quiz("ylp-20","How does Yelp prevent fake reviews (fraud detection)?","medium",("case-study",),
             ("Enforcing a strict limit of one review per user account per lifetime", "Automatically deleting all negative reviews that are under 100 characters", "Requiring every reviewer to upload a copy of their driver's license before posting", "Asynchronously analyzing user review patterns, IP addresses, check-in history, and text sentiment via fraud models"),3,
             "A fraud detection pipeline runs out-of-band to flags suspicious spikes, coordinated review groups, or check-in anomalies, keeping reviews trustworthy."),
    ))

